using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Server;
using Microsoft.AspNetCore.Components.Web;

namespace sv_db10d4b31d57406aa051365a12d55ccf.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that creates a hardcoded user
/// and persists the claims into PersistentComponentState so the WebAssembly
/// client can reconstruct the identity after the runtime switch.
/// </summary>
public sealed class PersistingAuthenticationStateProvider
    : ServerAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authStateTask;

    public PersistingAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        _persistentState = persistentState;

        // Build the hardcoded user identity.
        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, "bob@example.com"),
            new(ClaimTypes.Email, "bob@example.com"),
            new(ClaimTypes.Role, "User"),
            new(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        var user = new ClaimsPrincipal(identity);
        SetAuthenticationState(Task.FromResult(new AuthenticationState(user)));

        AuthenticationStateChanged += OnAuthenticationStateChanged;
        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveAuto);
    }

    private void OnAuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authStateTask = task;
    }

    private async Task OnPersistingAsync()
    {
        var authState = _authStateTask ?? GetAuthenticationStateAsync();
        var principal = (await authState).User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var claims = principal.Claims.Select(c => new ClaimData(c.Type, c.Value)).ToArray();
            _persistentState.PersistAsJson("UserClaims", claims);
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
        AuthenticationStateChanged -= OnAuthenticationStateChanged;
    }
}

public record ClaimData(string Type, string Value);

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_db10d4b31d57406aa051365a12d55ccf.Client.Auth;

/// <summary>
/// Client-side (WebAssembly) AuthenticationStateProvider that reads claims
/// persisted by the server via PersistentComponentState, ensuring the user's
/// identity survives the Server→WebAssembly runtime transition.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        if (persistentState.TryTakeFromJson<ClaimData[]>("UserClaims", out var claimData)
            && claimData is { Length: > 0 })
        {
            var claims = claimData.Select(c => new Claim(c.Type, c.Value));
            var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
            var user = new ClaimsPrincipal(identity);
            _authStateTask = Task.FromResult(new AuthenticationState(user));
        }
        else
        {
            _authStateTask = _unauthenticated;
        }
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync() => _authStateTask;
}

public record ClaimData(string Type, string Value);

